={{ (() => {
  const text = typeof $json.messageText === 'string' ? $json.messageText.trim() : '';
  const summaryUrl = typeof $json.summaryUrl === 'string' ? $json.summaryUrl.trim() : '';

  if (!summaryUrl) return text;

  const hasUrl = /https?:\/\/\S+/i.test(text);
  if (hasUrl) return text;

  return [
    text,
    'Link de agendamento: ' + summaryUrl,
  ].filter(Boolean).join('\n\n');
})() }}

