assignments.value:
={{ (() => {
  const output = $json.output;
  const steps = Array.isArray($json.intermediateSteps) ? $json.intermediateSteps : [];

  const sanitize = (text) => (typeof text === 'string' ? text : '')
    .trim()
    .replace(/confirma(c|ç)ão do agendamento/gi, 'geração do link de agendamento')
    .replace(/confirmar o agendamento/gi, 'gerar o link de agendamento')
    .replace(/consulta est[aá] agendada/gi, 'agendamento está pronto para conclusão')
    .replace(/consulta foi agendada/gi, 'agendamento está pronto para conclusão')
    .replace(/(\b\d{2}\/\d{2})\s*\([^\n)]*\)/g, '$1');

  const pickSummary = (value) => {
    if (value == null) return null;

    if (Array.isArray(value)) {
      for (const item of value) {
        const nested = pickSummary(item);
        if (nested) return nested;
      }
      return null;
    }

    if (typeof value !== 'object') return null;

    if (typeof value.summaryUrl === 'string' && value.summaryUrl.trim()) {
      return {
        summaryUrl: value.summaryUrl.trim(),
        valid: value.valid,
        ok: value.ok,
      };
    }

    if (value.data && typeof value.data === 'object') {
      const nested = pickSummary(value.data);
      if (nested) return nested;
    }

    if (value.response && typeof value.response === 'object') {
      const nested = pickSummary(value.response);
      if (nested) return nested;
    }

    return null;
  };

  // 1) Prioriza Structured Output Parser
  const structuredReply = typeof output === 'object' && output !== null ? sanitize(output.reply) : '';
  const structuredSummary = typeof output === 'object' && output !== null ? pickSummary(output) : null;

  if (structuredSummary?.summaryUrl && structuredSummary.ok !== false) {
    const hasSameUrl = structuredReply.includes(structuredSummary.summaryUrl);
    if (hasSameUrl) return structuredReply;

    return [
      structuredReply,
      'Link de agendamento: ' + structuredSummary.summaryUrl,
    ].filter(Boolean).join('\n\n');
  }

  if (structuredReply) return structuredReply;

  // 2) Fallback técnico: varre tool observations
  let latestToolResult = null;

  for (let i = steps.length - 1; i >= 0; i -= 1) {
    const observation = steps[i]?.observation;
    if (!observation) continue;

    if (typeof observation === 'object') {
      const extracted = pickSummary(observation);
      if (extracted) {
        latestToolResult = extracted;
        break;
      }
      continue;
    }

    if (typeof observation !== 'string') continue;

    try {
      const parsed = JSON.parse(observation);
      const extracted = pickSummary(parsed);
      if (extracted) {
        latestToolResult = extracted;
        break;
      }
    } catch {
      // Ignora observações não-JSON e segue buscando.
    }
  }

  const rawText = sanitize(typeof output === 'string' ? output : '');

  if (latestToolResult?.summaryUrl && latestToolResult.ok !== false) {
    const hasSameUrl = rawText.includes(latestToolResult.summaryUrl);
    if (hasSameUrl) return rawText;

    return [
      rawText,
      'Link de agendamento: ' + latestToolResult.summaryUrl,
    ].filter(Boolean).join('\n\n');
  }

  return rawText;
})() }}

